#include <bits/stdc++.h>

using namespace std;

class Solution {
 public:
  int solve(vector<int>& nums) {
    int n = nums.size();
    for (int i = 0; i < n; ++i) {
      while (i + 1 <= n && nums[i + 1] != i + 1) {
        swap(nums[i + 1], nums[n - 1]);
        n--;
      }
    }
    for (int i = 0; i < n; ++i) 
      if (nums[i] != i + 1) return i + 1;
    return n + 1;
  }
};

int main() {
  ios_base::sync_with_stdio(false);
  cin.tie(nullptr);
  cout.tie(nullptr);

  Solution obj;
  int n;
  cin >> n;

  vector<int> nums(n);
  for (int i = 0; i < n; ++i)
    cin >> nums[i];

  cout << obj.solve(nums) << '\n';
}

